
const PHOTO_URI = "data:image/jpeg;base64,";
const PDF_URI   = "data:application/pdf;base64,";

document.addEventListener('DOMContentLoaded', () => {
  // inject photo
  document.getElementById('hero-photo').src = PHOTO_URI;

  // inject pdf links
  document.querySelectorAll('.resume-dl').forEach(el => {
    el.href = PDF_URI;
  });

  // skill bar animation
  const skillSec = document.getElementById('skills-sec');
  if (skillSec) {
    const obs = new IntersectionObserver(entries => {
      entries.forEach(e => {
        if (e.isIntersecting) {
          e.target.querySelectorAll('.skill-bar').forEach(b => {
            b.style.width = b.dataset.w + '%';
          });
        }
      });
    }, {threshold: 0.3});
    obs.observe(skillSec);
  }

  // active nav
  const secs = document.querySelectorAll('section[id]');
  const links = document.querySelectorAll('.nav-links a');
  const navObs = new IntersectionObserver(entries => {
    entries.forEach(e => {
      if (e.isIntersecting) {
        links.forEach(l => l.classList.toggle('active', l.getAttribute('href') === '#'+e.target.id));
      }
    });
  }, {threshold: 0.4});
  secs.forEach(s => navObs.observe(s));

  // hamburger
  const hbg = document.getElementById('hamburger');
  const mm  = document.getElementById('mobile-menu');
  if (hbg && mm) {
    hbg.addEventListener('click', () => {
      mm.classList.toggle('open');
      hbg.classList.toggle('open');
    });
    mm.querySelectorAll('a').forEach(a => a.addEventListener('click', () => {
      mm.classList.remove('open');
      hbg.classList.remove('open');
    }));
  }
});
